B.KI=new A.aZ("pda_an_b2n","a\u207fb\xb2\u207f","Build a PDA that accepts strings of the form a\u207fb\xb2\u207f (n \u2265 1): for every a there must be exactly two b's.\nHint: push two markers for each a you read.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|X\n      n0 to n0 = a,\u2205|X\n      n0 to n1 = b,X|\u2205\n      n1 to n1 = b,X|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aM,null,B.aF,B.VU,0.5,"pda",!1,B.J,null,!1)
B.BM=new A.cb("pda_an_b2n")
B.KL=new A.aZ("level_2","Level 2 \u2014 PDA Boss","Build a PDA that matches the hidden stack-based target machine. Study the transition format and think carefully about what language this could be.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = <<ha>>\n      n4 = E\n      n5 = F\n      n0 = (723.3, 204.7)\n      n1 = (1139.3, 259.3)\n      n2 = (1196.0, 527.3)\n      n3 = (739.3, 705.3)\n      n4 = (345.3, 504.7)\n      n5 = (345.3, 277.3)\n      n0 to n5 = 0,~|X\n      n0 to n1 = 1,~|Y\n      n1 to n1 = 1,~|Y\n      n1 to n2 = 0,Y|~\n      n2 to n1 = 1,\u2205|Y\n      n2 to n5 = 0,\u2205|X\n      n4 to n1 = 1,\u2205|Y\n      n4 to n5 = 0,\u2205|X\n      n5 to n4 = 1,X|~\n      n5 to n5 = 0,~|X\n      n4 to n4 = 1,X|~\n      n4 to n3 = \u2205,\u2205|~\n      n2 to n3 = \u2205,\u2205|~\n      n2 to n2 = 0,Y|~\n      l0(0,~|X) curve = -2.9\n      l3(0,Y|~) curve = 62.2\n      l4(1,\u2205|Y) curve = 55.1\n      l5(0,\u2205|X) curve = 39.9\n      l6(1,\u2205|Y) curve = 16.9\n      l7(0,\u2205|X) curve = -8.2\n      l8(1,X|~) curve = -105.4\n      l2(1,~|Y) loop angle = -0.7988\n      l9(0,~|X) loop angle = -1.5708\n      l10(1,X|~) loop angle = 1.7686\n      l13(0,Y|~) loop angle = -0.0754\n      to n0 angle = -1.0000, 0.0000\n    ",B.aM,null,B.b9,B.BM,0.25,"pda",!1,B.J,null,!1)
B.L1=new A.aZ("pda_palindrome","PDA Palindromes","Build a PDA over {a, b} that accepts even-length palindromes (ww^R where w is any string over {a,b}).\nHint: push the first half onto the stack, then pop-match the second half.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|a\n      n0 to n0 = b,\u2205|b\n      n0 to n1 = \u2205,\u2205|\u2205\n      n1 to n1 = a,a|\u2205\n      n1 to n1 = b,b|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aM,null,B.b9,B.BM,0.75,"pda",!1,B.J,null,!1)
B.PC=s(["level_2","pda_palindrome"],t.s)
B.Vv=new A.hA(B.PC)
B.a3r=new A.ii(8,"tmTape")
B.a3x=new A.e1("The Turing Machine","A Turing machine adds a **read/write tape** to a finite automaton. The tape is infinite in both directions and starts with your input.\n\nA **read/write head** sits on one cell at a time. On each step it reads the current symbol, writes a new symbol (or leaves it), and moves **Left** or **Right** (or stays Still).",B.a3r)
B.a3w=new A.e1("TM Transition Format",'Each TM arrow label has the format:\n\n  **readSymbol writeSymbol Direction**\n\nDirection is **R** (right), **L** (left), or **S** (stay).\n\nExample: **"aXR"** \u2014 read "a", write "X", move Right.\nExample: **"\u2205\u2205S"** \u2014 read blank, write blank, stay (blank = empty cell).',B.ck)
B.a3M=new A.e1("Accepting and Rejecting","A TM **accepts** by entering an accept state (double ring) and halting.\n\nA TM **rejects** either by entering a reject state (no outgoing transition for the current symbol causes a crash) or by looping forever.\n\nThe equivalence checker uses a bounded simulation \u2014 it tests many input strings but can't always prove correctness on all inputs.",B.ck)
B.a3F=new A.e1("The Crossout Technique",'Many TM puzzles use a **crossout** strategy:\n\n1. Replace a matched symbol with **X** (or another marker) to "cross it out".\n2. Sweep the tape left/right to find the next unmatched symbol.\n3. Repeat until all symbols are matched or a mismatch is detected.\n\nYou\'ll see this in a\u207fb\u207f, a\u207fb\u207fc\u207f, palindrome, and the "ww" puzzles.',B.ck)
B.a3y=new A.e1("Multiple Loops on One State","TM states often have **many self-loops** \u2014 one for each symbol the machine should pass over without stopping.\n\nIn the canvas you can drag a self-loop's label dot to rotate it around the state circle, so diagrams stay readable even with 4\u20135 loops on one state.",B.ck)
B.Pv=s([B.a3x,B.a3w,B.a3M,B.a3F,B.a3y],t.nY)
B.KJ=new A.aZ("tutorial_tm","Turing Machines","Learn the read/write tape model and TM transition format.","",B.I,null,B.b9,B.Vv,0.5,"tutorial",!0,B.Pv,null,!1)
B.BO=new A.cb("tutorial_tm")
B.KW=new A.aZ("tm_identity","TM: Accept All (Trivial)","Build the simplest possible Turing machine: one that accepts every input by halting immediately.\nA single state that is both start and accept will do it. TM transition format: readSymbol writeSymbol Direction (e.g. aBR = read a, write B, move Right).","      tm mode\n      n0 = A\n      A = (600.0, 360.0)\n      A is accepted\n      to A angle = -1.0000, 0.0000\n    ",B.aY,null,B.b9,B.BO,0.25,"tm",!1,B.J,null,!1)
B.L3=new A.aZ("tm_reject_all","TM: Reject All","Build a TM that loops forever on any non-empty input (rejects by non-halt) and accepts only the empty tape.\nHint: a start state with a self-loop on every symbol that moves right will spin forever.","      tm mode\n      n0 = A\n      n1 = B\n      A = (480.0, 360.0)\n      B = (820.0, 360.0)\n      B is accepted\n      A to B = \u2205\u2205S\n      to A angle = -1.0000, 0.0000\n    ",B.aY,null,B.b9,B.BO,0.75,"tm",!1,B.J,null,!1)
B.PL=s(["tm_identity","tm_reject_all"],t.s)
B.Vt=new A.hz(B.PL)
B.Lo=new A.aZ("tm_anbn","TM: a\u207fb\u207f","Build a TM that accepts exactly strings of the form a\u207fb\u207f (n \u2265 1). Classic TM exercise: repeatedly cross off one a and one b until both sides are exhausted.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      A = (260.0, 200.0)\n      B = (660.0, 200.0)\n      C = (1060.0, 200.0)\n      D = (660.0, 560.0)\n      E = (260.0, 560.0)\n      E is accepted\n      A to B = aXR\n      B to B = aXR\n      B to C = bXL\n      C to D = XXL\n      D to D = aXL\n      D to A = XXR\n      A to E = \u2205\u2205S\n      l1(aXR) loop angle = -1.5708\n      l3(XXL) loop angle = -1.5708\n      l4(aXL) loop angle = 1.5708\n      aXR curve = 80.0\n      bXL curve = 80.0\n      XXR curve = 80.0\n      to A angle = -1.0000, 0.0000\n    ",B.aY,null,B.b9,B.Vt,0.5,"tm",!1,B.J,null,!1)
B.VV=new A.cb("tm_anbn")
B.KN=new A.aZ("tm_anbncn","TM: a\u207fb\u207fc\u207f","Build a TM that accepts strings of the form a\u207fb\u207fc\u207f (n \u2265 1).\nThis language is not context-free \u2014 no PDA can recognise it \u2014 but a TM can! Cross off one a, one b, and one c per pass.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 200.0)\n      B = (580.0, 200.0)\n      C = (900.0, 200.0)\n      D = (900.0, 540.0)\n      E = (580.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      B to B = aaR\n      B to B = XXR\n      B to C = bXR\n      C to C = bbR\n      C to C = XXR\n      C to D = cXL\n      D to D = bbL\n      D to D = ccL\n      D to D = XXL\n      D to E = aaL\n      E to E = aaL\n      E to E = bbL\n      E to E = ccL\n      E to E = XXL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(XXR) loop angle = -0.8000\n      l4(bbR) loop angle = -1.5708\n      l5(XXR) loop angle = -0.8000\n      l7(bbL) loop angle = 1.5708\n      l8(ccL) loop angle = 0.8000\n      l9(XXL) loop angle = 2.3000\n      l11(aaL) loop angle = 1.5708\n      l12(bbL) loop angle = 0.8000\n      l13(ccL) loop angle = 2.3000\n      l14(XXL) loop angle = 3.1000\n      aXR curve = 70.0\n      bXR curve = 70.0\n      cXL curve = 70.0\n      aaL_E curve = 60.0\n      XXR_E curve = 60.0\n      to A angle = -1.0000, 0.0000\n    ",B.aY,null,B.b9,B.VV,0.5,"tm",!1,B.J,null,!1)
B.VW=new A.cb("tm_anbncn")
B.KZ=new A.aZ("tm_ww","TM: ww (Doubled Word)",'Build a TM that accepts strings of the form ww over {a, b}: a string that consists of some word w repeated exactly twice (e.g. "abab", "aabb aabb"). This is a classic non-context-free language.',"      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 180.0)\n      B = (660.0, 180.0)\n      C = (1060.0, 180.0)\n      D = (1060.0, 540.0)\n      E = (660.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      A to C = bXR\n      B to B = aaR\n      B to B = bbR\n      B to D = bXL\n      C to C = aaR\n      C to C = bbR\n      C to E = aXL\n      D to D = aaL\n      D to D = bbL\n      D to A = XXR\n      E to E = aaL\n      E to E = bbL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(bbR) loop angle = -0.8000\n      l5(aaR) loop angle = -1.5708\n      l6(bbR) loop angle = -0.8000\n      l7(aaL) loop angle = 1.5708\n      l8(bbL) loop angle = 0.8000\n      l10(aaL) loop angle = 1.5708\n      l11(bbL) loop angle = 0.8000\n      aXR curve = 60.0\n      bXR curve = -60.0\n      bXL curve = 60.0\n      aXL curve = -60.0\n      XXR_D curve = 80.0\n      XXR_E curve = -80.0\n      to A angle = -1.0000, 0.0000\n    ",B.aY,null,B.b9,B.VW,0.5,"tm",!1,B.J,null,!1)
B.VX=new A.cb("tm_ww")
B.Ls=new A.aZ("tm_palindrome","TM: Palindrome","Build a TM over {a, b} that accepts palindromes of any length.\nStrategy: repeatedly peel the first and last character and verify they match.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 200.0)\n      B = (640.0, 200.0)\n      C = (1020.0, 200.0)\n      D = (1020.0, 540.0)\n      E = (640.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      A to C = bXR\n      B to B = aaR\n      B to B = bbR\n      B to E = aXL\n      C to C = aaR\n      C to C = bbR\n      C to D = bXL\n      D to D = aaL\n      D to D = bbL\n      D to A = XXR\n      E to E = aaL\n      E to E = bbL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(bbR) loop angle = -0.6000\n      l5(aaR) loop angle = -1.5708\n      l6(bbR) loop angle = -0.6000\n      l8(aaL) loop angle = 1.5708\n      l9(bbL) loop angle = 0.6000\n      l11(aaL) loop angle = 1.5708\n      l12(bbL) loop angle = 0.6000\n      aXR curve = 70.0\n      bXR curve = -70.0\n      aXL curve = -70.0\n      bXL curve = 70.0\n      to A angle = -1.0000, 0.0000\n    ",B.aY,null,B.b9,B.VX,0.5,"tm",!1,B.J,null,!1)
